import { chromium } from 'playwright';
const b = await chromium.launch();
const p = await b.newPage();
await p.setViewportSize({ width: 1200, height: 630 });

await p.setContent(`
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  * { margin:0; padding:0; box-sizing:border-box; font-family: 'Helvetica Neue', Arial, sans-serif; }
  body {
    width: 1200px; height: 630px;
    background: #0a0a0a;
    display: flex; align-items: center; justify-content: space-between;
    padding: 64px 80px;
    overflow: hidden;
  }
  .left { display: flex; flex-direction: column; gap: 0; }
  .tag { font-size: 13px; letter-spacing: 0.22em; color: rgba(255,255,255,0.4); text-transform: uppercase; margin-bottom: 24px; }
  .logo-row { display: flex; align-items: center; gap: 20px; margin-bottom: 36px; }
  .logo-row img { width: 72px; height: 72px; object-fit: contain; }
  .wordmark { display: flex; flex-direction: column; gap: 4px; }
  .w-korea { font-size: 13px; letter-spacing: 0.28em; color: rgba(255,255,255,0.45); text-transform: uppercase; }
  .w-koition { font-size: 36px; font-weight: 700; letter-spacing: 0.1em; color: #fff; }
  .w-innovation { font-size: 12px; letter-spacing: 0.22em; color: #FF0000; text-transform: uppercase; }
  .headline { font-size: 28px; font-weight: 700; color: #fff; line-height: 1.3; max-width: 480px; margin-bottom: 20px; }
  .sub { font-size: 16px; color: rgba(255,255,255,0.5); line-height: 1.6; max-width: 460px; }
  .right { display: flex; flex-direction: column; align-items: flex-end; gap: 16px; }
  .badge { background: #FF0000; color: #fff; padding: 10px 22px; border-radius: 4px; font-size: 13px; font-weight: 600; letter-spacing: 0.06em; }
  .url { font-size: 14px; color: rgba(255,255,255,0.3); letter-spacing: 0.06em; }
  .divider { width: 1px; height: 200px; background: rgba(255,255,255,0.08); align-self: center; margin: 0 60px; }
  .stats { display: flex; flex-direction: column; gap: 20px; }
  .stat-val { font-size: 32px; font-weight: 700; color: #fff; }
  .stat-label { font-size: 11px; color: #FF0000; letter-spacing: 0.12em; text-transform: uppercase; margin-top: 2px; }
  .accent-line { width: 40px; height: 3px; background: #FF0000; margin-bottom: 32px; }
</style>
</head>
<body>
  <div class="left">
    <div class="tag">Korea · Innovation · Data Engineering</div>
    <div class="logo-row">
      <img src="data:image/png;base64," />
      <div class="wordmark">
        <span class="w-korea">Korea</span>
        <span class="w-koition">Koition</span>
        <span class="w-innovation">Innovation</span>
      </div>
    </div>
    <div class="accent-line"></div>
    <div class="headline">디지털 대전환의 기준을<br>코이션이 다시 정의합니다.</div>
    <div class="sub">기록물 전산화 · AI 지능형 플랫폼 · 데이터 전 생애주기 관리</div>
  </div>
  <div class="divider"></div>
  <div class="right">
    <div class="stats">
      <div>
        <div class="stat-val">1,000만+</div>
        <div class="stat-label">Data Archived</div>
      </div>
      <div>
        <div class="stat-val">99.9%</div>
        <div class="stat-label">Data Integrity</div>
      </div>
      <div>
        <div class="stat-val">GS 1등급</div>
        <div class="stat-label">Quality Certified</div>
      </div>
    </div>
    <div class="badge">koition.co.kr</div>
    <div class="url">© 2026 KOITION Co., Ltd.</div>
  </div>
</body>
</html>
`);

await p.screenshot({ path: 'C:/Users/ocm/koition-site/public/og-image.png' });
console.log('OG image done');
await b.close();

